6	
7	function DiffWorkerThemeSync({ themeName }: { themeName: DiffThemeName }) {
8	  const workerPool = useWorkerPool();
9	
10	  useEffect(() => {
11	    if (!workerPool) {
12	      return;
13	    }
14	
15	    const current = workerPool.getDiffRenderOptions();
16	    if (current.theme === themeName) {
17	      return;
18	    }
19	
20	    void workerPool
21	      .setRenderOptions({
22	        ...current,
23	        theme: themeName,
24	      })
25	      .catch(() => undefined);
26	  }, [themeName, workerPool]);
27	
28	  return null;
29	}
30	
31	export function DiffWorkerPoolProvider({ children }: { children?: ReactNode }) {
32	  const { resolvedTheme } = useTheme();
33	  const diffThemeName = resolveDiffThemeName(resolvedTheme);
34	  const workerPoolSize = useMemo(() => {
35	    const cores =
36	      typeof navigator === "undefined" ? 4 : Math.max(1, navigator.hardwareConcurrency || 4);
37	    return Math.max(2, Math.min(6, Math.floor(cores / 2)));
38	  }, []);
39	
40	  return (
41	    <WorkerPoolContextProvider
42	      poolOptions={{
43	        workerFactory: () => new DiffsWorker(),
44	        poolSize: workerPoolSize,
45	        totalASTLRUCacheSize: 240,
46	      }}
47	      highlighterOptions={{
48	        theme: diffThemeName,
49	        tokenizeMaxLineLength: 1_000,
50	      }}
51	    >
52	      <DiffWorkerThemeSync themeName={diffThemeName} />
53	      {children}
54	    </WorkerPoolContextProvider>
55	  );
56	}
