100	        throw new Error("Checkpoint diff is unavailable.");
101	      }
102	      try {
103	        if (decodedRequest.value.kind === "fullThreadDiff") {
104	          return await api.orchestration.getFullThreadDiff(decodedRequest.value.input);
105	        }
106	        return await api.orchestration.getTurnDiff(decodedRequest.value.input);
107	      } catch (error) {
108	        throw new Error(normalizeCheckpointErrorMessage(error), { cause: error });
109	      }
110	    },
111	    enabled: (input.enabled ?? true) && !!input.threadId && decodedRequest._tag === "Some",
112	    staleTime: Infinity,
