import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  THEME_COLOR_KEYS,
  findBuiltInTheme,
  type ThemeAppearance,
  type ThemeColors,
  type ThemeDefinition,
} from "@t3tools/shared/theme";

// ── Constants ───────────────────────────────────────────────────────────────

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/**
 * Convert a `ThemeColors` key to its CSS custom property name.
 * camelCase → kebab-case prefixed with `--theme-`.
 *
 * e.g. `statusBarForeground` → `--theme-status-bar-foreground`
 */
function cssVarName(token: string): string {
  return `--theme-${token.replace(/[A-Z]/g, (ch) => `-${ch.toLowerCase()}`)}`;
}

// ── External store (singleton, lives outside React) ─────────────────────────

interface ThemeSnapshot {
  /** The raw persisted value – a theme ID or `"system"`. */
  themeId: string;
  /** Whether the OS currently prefers dark (only relevant when `themeId === "system"`). */
  systemDark: boolean;
}

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Read the persisted theme ID from localStorage, migrating legacy
 * `"light"` / `"dark"` / `"system"` values to the new theme IDs.
 */
function getStoredId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return DEFAULT_THEME_ID;

  // Migrate legacy values from the old light/dark/system picker
  if (raw === "dark") return "t3-dark";
  if (raw === "light") return "t3-light";
  if (raw === "system") return "system";

  // Validate against known themes
  return findBuiltInTheme(raw) ? raw : DEFAULT_THEME_ID;
}

/** Resolve a stored ID into the concrete `ThemeDefinition` to apply. */
function resolveTheme(storedId: string, systemDark: boolean): ThemeDefinition {
  if (storedId === "system") {
    return findBuiltInTheme(systemDark ? "t3-dark" : "t3-light")!;
  }
  return findBuiltInTheme(storedId) ?? findBuiltInTheme(DEFAULT_THEME_ID)!;
}

// ── DOM side-effects ────────────────────────────────────────────────────────

function applyCssProperties(colors: ThemeColors): void {
  const style = document.documentElement.style;
  for (const token of THEME_COLOR_KEYS) {
    style.setProperty(cssVarName(token), colors[token]);
  }
}

function applyTheme(storedId: string, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const systemDark = getSystemDark();
  const theme = resolveTheme(storedId, systemDark);

  document.documentElement.classList.toggle("dark", theme.appearance === "dark");
  applyCssProperties(theme.colors);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStoredId());

// ── Snapshot for useSyncExternalStore ────────────────────────────────────────

function getSnapshot(): ThemeSnapshot {
  const themeId = getStoredId();
  const systemDark = themeId === "system" ? getSystemDark() : false;

  if (lastSnapshot && lastSnapshot.themeId === themeId && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredId() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ── Hook ────────────────────────────────────────────────────────────────────

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { themeId, systemDark } = snapshot;

  const activeTheme: ThemeDefinition = resolveTheme(themeId, systemDark);
  const resolvedAppearance: ThemeAppearance = activeTheme.appearance;

  const setThemeId = useCallback((next: string) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount and when the themeId changes
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return {
    /** The persisted theme selection (a theme ID or `"system"`). */
    themeId,
    /** Update the active theme. Pass a built-in theme ID or `"system"`. */
    setThemeId,
    /** The fully resolved `ThemeDefinition` currently in effect. */
    activeTheme,
    /** All available built-in themes. */
    themes: BUILT_IN_THEMES,

    // ── Backward-compatible surface ──
    /** Alias for `themeId`. */
    theme: themeId,
    /** Alias for `setThemeId`. */
    setTheme: setThemeId,
    /** Resolved appearance – always `"light"` or `"dark"`. */
    resolvedTheme: resolvedAppearance,
  } as const;
}

