function ThemeSwatch({ theme }: { theme: ThemeDefinition }) {
  const { colors } = theme;
  return (
    <div
      className="flex h-10 w-16 shrink-0 overflow-hidden rounded-md border border-border"
      aria-hidden="true"
    >
