      {/* Editor + terminal column */}
      <div className="flex flex-1 flex-col">
        <div className="flex-1" style={{ backgroundColor: colors.editor }} />
        <div className="flex-1" style={{ backgroundColor: colors.terminal }} />
      </div>
    </div>
  );
}

