        <div className="h-1.5" style={{ backgroundColor: dark.colors.statusBar }} />
      </div>
    </div>
  );
}

// ── Selector ────────────────────────────────────────────────────────────────

interface ThemeOption {
  id: string;
  name: string;
  description: string;
  swatch: React.ReactNode;
}

const THEME_OPTIONS: ThemeOption[] = [
  {
