    name: theme.name,
    description: `${theme.appearance === "light" ? "Light" : "Dark"} theme with a ${theme.name.toLowerCase()} palette.`,
    swatch: <ThemeSwatch theme={theme} />,
  })),
];

/**
 * Theme picker with mini layout-preview swatches for each built-in theme
 * plus a "System" option that follows the OS preference.
 */
export function ThemeSelector() {
  const { themeId, setThemeId, resolvedTheme } = useTheme();

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
        {THEME_OPTIONS.map((option) => {
          const selected = themeId === option.id;
          return (
            <button
              key={option.id}
              type="button"
              role="radio"
              aria-checked={selected}
              className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent"
              }`}
              onClick={() => setThemeId(option.id)}
            >
              {option.swatch}
              <span className="flex flex-1 flex-col">
                <span className="text-sm font-medium">{option.name}</span>
                <span className="text-xs">{option.description}</span>
              </span>
              {selected ? (
                <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active appearance: <span className="font-medium text-foreground">{resolvedTheme}</span>
      </p>
    </div>
  );
}

